#pragma once

#include <cstddef>
#include <tuple> // IWYU pragma: keep
#include <utility>

namespace threadschedule::reflect
{

/**
 * @brief Descriptor for struct reflection (compile-time metadata).
 * Specializations are generated by THREADSCHEDULE_REFLECTION_DEFINE_STRUCT_REFLECT_HELPER; do not specialize manually.
 */
template <typename T>
struct descriptor
{
    static constexpr std::size_t size = 0;
};

template <typename T>
struct member_count
{
    static constexpr std::size_t value = descriptor<T>::size;
};

template <typename T>
inline constexpr std::size_t member_count_v = member_count<T>::value;

namespace detail
{
template <typename T, typename F, std::size_t... I>
void for_each_member_impl(T& obj, F&& f, std::index_sequence<I...> /*unused*/)
{
    using D = descriptor<T>;
    (void)(f(D::names[I], obj.*std::get<I>(D::ptrs)), ...);
}

template <typename T, typename F, std::size_t... I>
void for_each_member_impl(T const& obj, F&& f, std::index_sequence<I...> /*unused*/)
{
    using D = descriptor<T>;
    (void)(f(D::names[I], obj.*std::get<I>(D::ptrs)), ...);
}
} // namespace detail

/**
 * @brief Invoke @a f for each reflected member of @a obj.
 *
 * @a f is called as f(const char* name, MemberType& value) for each member.
 * Use THREADSCHEDULE_REFLECTION_DEFINE_STRUCT_REFLECT_HELPER to define the type (no separate REFLECT macro).
 */
template <typename T, typename F>
void for_each_member(T& obj, F&& f)
{
    using D = descriptor<T>;
    if constexpr (D::size > 0)
        detail::for_each_member_impl(obj, std::forward<F>(f), std::make_index_sequence<D::size>{});
}

template <typename T, typename F>
void for_each_member(T const& obj, F&& f)
{
    using D = descriptor<T>;
    if constexpr (D::size > 0)
        detail::for_each_member_impl(obj, std::forward<F>(f), std::make_index_sequence<D::size>{});
}

/**
 * @brief Name of the I-th reflected member (0-based). Only valid when I < member_count_v<T>.
 */
template <typename T, std::size_t I>
constexpr auto get_member_name() -> char const*
{
    static_assert(I < descriptor<T>::size, "member index out of range");
    return descriptor<T>::names[I];
}

} // namespace threadschedule::reflect

