#define THREADSCHEDULE_REFLECTION_PAIR_FIRST(a, b) a
#define THREADSCHEDULE_REFLECTION_PAIR_SECOND(a, b) b
#define THREADSCHEDULE_REFLECTION_STRINGIZE(x) #x

