#define THREADSCHEDULE_REFLECTION_DS_VA_NARGS_IMPL(_1, _2, _3, _4, _5, _6, _7, _8, N, ...) N
#define THREADSCHEDULE_REFLECTION_DS_VA_NARGS(...)                                                                     \
    THREADSCHEDULE_REFLECTION_DS_VA_NARGS_IMPL(__VA_ARGS__, 8, 7, 6, 5, 4, 3, 2, 1)

#define THREADSCHEDULE_REFLECTION_DEFINE_STRUCT_REFLECT_HELPER_DISPATCH(N, Name, ...)                                  \
    THREADSCHEDULE_REFLECTION_DS_##N(Name, __VA_ARGS__)
#define THREADSCHEDULE_REFLECTION_DEFINE_STRUCT_REFLECT_HELPER_INNER(N, Name, ...)                                     \
    THREADSCHEDULE_REFLECTION_DEFINE_STRUCT_REFLECT_HELPER_DISPATCH(N, Name, __VA_ARGS__)

/**
 * @brief Define a struct and its reflection in one place. Write each member once as (Type, name).
 *
 * No separate REFLECT macro; the member list is the single source of truth.
 *
 * @code
 *   THREADSCHEDULE_DEFINE_STRUCT_REFLECTION(Point, (int, x), (int, y));
 *   THREADSCHEDULE_DEFINE_STRUCT_REFLECTION(Config, (std::string, name), (int, threads), (bool, enabled));
 * @endcode
 *
 * Supports 1 to 8 members. Then use reflect::for_each_member(obj, lambda) as usual.
 */
#define THREADSCHEDULE_DEFINE_STRUCT_REFLECTION(Name, ...)                                                             \
    THREADSCHEDULE_REFLECTION_DEFINE_STRUCT_REFLECT_HELPER_INNER(THREADSCHEDULE_REFLECTION_DS_VA_NARGS(__VA_ARGS__),   \
                                                                 Name, __VA_ARGS__)

// --- BEGIN/END: same member list, but you can add methods between BEGIN and END ---

