#define THREADSCHEDULE_REFLECTION_END_DISPATCH(N, Name, ...) THREADSCHEDULE_REFLECTION_END_##N(Name, __VA_ARGS__)
#define THREADSCHEDULE_REFLECTION_BEGIN_DISPATCH(N, Name, ...) THREADSCHEDULE_REFLECTION_BEGIN_##N(Name, __VA_ARGS__)

/* Extra indirection so N is expanded before BEGIN_##N / END_##N paste. */
#define THREADSCHEDULE_DEFINE_STRUCT_BEGIN_INNER(N, Name, ...)                                                          \
    THREADSCHEDULE_REFLECTION_BEGIN_DISPATCH(N, Name, __VA_ARGS__)
#define THREADSCHEDULE_DEFINE_STRUCT_END_INNER(N, Name, ...)                                                           \
    THREADSCHEDULE_REFLECTION_END_DISPATCH(N, Name, __VA_ARGS__)

/**
 * @brief Start a struct definition with reflected members. Add methods, then close with THREADSCHEDULE_DEFINE_STRUCT_END.
 *
 * Member list must be repeated in END (same as in BEGIN).
 *
 * @code
 *   THREADSCHEDULE_DEFINE_STRUCT_BEGIN(Point, (int, x), (int, y))
 *       void scale(int s) { x *= s; y *= s; }
 *       int sum() const { return x + y; }
 *   THREADSCHEDULE_DEFINE_STRUCT_END(Point, (int, x), (int, y))
 * @endcode
 */
#define THREADSCHEDULE_DEFINE_STRUCT_BEGIN(Name, ...)                                                                  \
    THREADSCHEDULE_DEFINE_STRUCT_BEGIN_INNER(THREADSCHEDULE_REFLECTION_DS_VA_NARGS(__VA_ARGS__), Name, __VA_ARGS__)

#define THREADSCHEDULE_DEFINE_STRUCT_END(Name, ...)                                                                    \
    THREADSCHEDULE_DEFINE_STRUCT_END_INNER(THREADSCHEDULE_REFLECTION_DS_VA_NARGS(__VA_ARGS__), Name, __VA_ARGS__)

// --- Single macro: members once + method body (wrap body in THREADSCHEDULE_BODY(...) so commas in methods are ok) ---

#define THREADSCHEDULE_BODY(x) x

#define THREADSCHEDULE_DEFINE_STRUCT_WITH_METHODS_1(Name, p1, body)                                                    \
    THREADSCHEDULE_REFLECTION_BEGIN_1(Name, p1) body THREADSCHEDULE_REFLECTION_END_1(Name, p1)
#define THREADSCHEDULE_DEFINE_STRUCT_WITH_METHODS_2(Name, p1, p2, body)                                                 \
    THREADSCHEDULE_REFLECTION_BEGIN_2(Name, p1, p2) body THREADSCHEDULE_REFLECTION_END_2(Name, p1, p2)
