#define THREADSCHEDULE_DEFINE_STRUCT_WITH_METHODS_7(Name, p1, p2, p3, p4, p5, p6, p7, body)                            \
    THREADSCHEDULE_REFLECTION_BEGIN_7(Name, p1, p2, p3, p4, p5, p6, p7) body THREADSCHEDULE_REFLECTION_END_7(Name, p1, p2, p3, p4, p5, p6, p7)
#define THREADSCHEDULE_DEFINE_STRUCT_WITH_METHODS_8(Name, p1, p2, p3, p4, p5, p6, p7, p8, body)                        \
    THREADSCHEDULE_REFLECTION_BEGIN_8(Name, p1, p2, p3, p4, p5, p6, p7, p8) body THREADSCHEDULE_REFLECTION_END_8(Name, p1, p2, p3, p4, p5, p6, p7, p8)

#define THREADSCHEDULE_DEFINE_STRUCT_WITH_METHODS_DISPATCH(N, Name, ...)                                                \
    THREADSCHEDULE_DEFINE_STRUCT_WITH_METHODS_##N(Name, __VA_ARGS__)
#define THREADSCHEDULE_DEFINE_STRUCT_WITH_METHODS_INNER(N, Name, ...)                                                   \
    THREADSCHEDULE_DEFINE_STRUCT_WITH_METHODS_DISPATCH(N, Name, __VA_ARGS__)

/**
 * @brief Struct with reflected members and methods in one macro. Member list written once; N = number of members.
 *
 * Wrap the method block in THREADSCHEDULE_BODY(...) so commas in method signatures don't break the macro.
 *
 * @code
 *   THREADSCHEDULE_DEFINE_STRUCT_WITH_METHODS(Point, 2, (int, x), (int, y), THREADSCHEDULE_BODY(
 *       void scale(int s) { x *= s; y *= s; }
 *       int sum() const { return x + y; }
 *   ))
 * @endcode
 */
#define THREADSCHEDULE_DEFINE_STRUCT_WITH_METHODS(Name, N, ...)                                                         \
    THREADSCHEDULE_DEFINE_STRUCT_WITH_METHODS_INNER(N, Name, __VA_ARGS__)
